// // This module is designed to capture the input signal 'clk' on the rising edge of the clock signal 'dato' and update the output 'q' to reflect the value of 'clk'. The output 'q' maintains the captured value until the next rising edge of the clock.
module top_module(dato,clk,q);input dato, clk; 
output reg q;

always @ ( posedge clk)
begin
  q <= dato;
end
endmodule
